import { BnGovernanceMapping, BnGovernanceMappingStore } from '@binom/sdk-governance/types';

export interface BnGovernanceMappingStoreConfig {
  defaultTtlMs?: number;
  maxEntries?: number;
}

function isMappingExpired(
  mapping: BnGovernanceMapping,
  referenceDate: Date = new Date(),
): boolean {
  const expiresAt = mapping.meta?.expiresAt;
  if (!expiresAt) {
    return false;
  }
  return referenceDate.getTime() >= Date.parse(expiresAt);
}

export class BnInMemoryGovernanceMappingStore implements BnGovernanceMappingStore {
  private readonly entries = new Map<string, BnGovernanceMapping>();
  private readonly defaultTtlMs?: number;
  private readonly maxEntries?: number;

  constructor(config?: BnGovernanceMappingStoreConfig) {
    this.defaultTtlMs = config?.defaultTtlMs;
    this.maxEntries = config?.maxEntries;
  }

  save(mapping: BnGovernanceMapping): void {
    const createdAt = mapping.meta.createdAt ?? new Date().toISOString();
    const expiresAt =
      mapping.meta.expiresAt ??
      (this.defaultTtlMs
        ? new Date(Date.parse(createdAt) + this.defaultTtlMs).toISOString()
        : undefined);

    const normalized: BnGovernanceMapping = {
      ...mapping,
      meta: {
        ...mapping.meta,
        createdAt,
        expiresAt,
      },
    };

    this.entries.set(normalized.id, normalized);
    this.enforceMaxEntries();
  }

  get(id: string): BnGovernanceMapping | undefined {
    const mapping = this.entries.get(id);
    if (!mapping) {
      return undefined;
    }
    if (isMappingExpired(mapping)) {
      return undefined;
    }
    return mapping;
  }

  delete(id: string): void {
    this.entries.delete(id);
  }

  clearExpiredMappings(referenceDate: Date = new Date()): number {
    let removed = 0;
    for (const [id, mapping] of this.entries.entries()) {
      if (isMappingExpired(mapping, referenceDate)) {
        this.entries.delete(id);
        removed += 1;
      }
    }
    return removed;
  }

  listIds(): string[] {
    return [...this.entries.keys()];
  }

  private enforceMaxEntries(): void {
    if (!this.maxEntries || this.entries.size <= this.maxEntries) {
      return;
    }
    const sorted = [...this.entries.values()].sort((a, b) =>
      Date.parse(a.meta.createdAt) - Date.parse(b.meta.createdAt),
    );
    while (this.entries.size > this.maxEntries) {
      const oldest = sorted.shift();
      if (!oldest) {
        break;
      }
      this.entries.delete(oldest.id);
    }
  }
}

export function createMappingStore(
  config?: BnGovernanceMappingStoreConfig,
): BnGovernanceMappingStore {
  return new BnInMemoryGovernanceMappingStore(config);
}

export function clearExpiredMappings(
  store: BnGovernanceMappingStore,
  referenceDate?: Date,
): number {
  return store.clearExpiredMappings(referenceDate);
}
